利用FastAPI的内置文档生成功能，结合自定义文档增强，创建全面的API文档。

1. 配置FastAPI文档：
```python
from fastapi import FastAPI
from fastapi.openapi.docs import get_swagger_ui_html, get_redoc_html
from fastapi.openapi.utils import get_openapi

app = FastAPI(
    title="优化API",
    description="增强的后端API，实现了缓存、分页、安全和异步操作",
    version="1.0.0",
    docs_url=None,  # 禁用默认的文档URL
    redoc_url=None  # 禁用默认的ReDoc URL
)

@app.get("/docs", include_in_schema=False)
async def custom_swagger_ui_html():
    return get_swagger_ui_html(
        openapi_url=app.openapi_url,
        title=f"{app.title} - Swagger UI",
        oauth2_redirect_url=app.swagger_ui_oauth2_redirect_url,
        swagger_js_url="https://cdn.jsdelivr.net/npm/swagger-ui-dist@5.9.0/swagger-ui-bundle.js",
        swagger_css_url="https://cdn.jsdelivr.net/npm/swagger-ui-dist@5.9.0/swagger-ui.css",
    )

@app.get("/redoc", include_in_schema=False)
async def redoc_html():
    return get_redoc_html(
        openapi_url=app.openapi_url,
        title=f"{app.title} - ReDoc",
        redoc_js_url="https://cdn.jsdelivr.net/npm/redoc@next/bundles/redoc.standalone.js",
    )
```

2. 自定义OpenAPI生成：
```python
def custom_openapi():
    if app.openapi_schema:
        return app.openapi_schema

    openapi_schema = get_openapi(
        title=app.title,
        version=app.version,
        description=app.description,
        routes=app.routes,
    )

    # 添加API密钥安全方案
    openapi_schema["components"]["securitySchemes"] = {
        "ApiKeyAuth": {
            "type": "apiKey",
            "in": "header",
            "name": "X-API-Key"
        },
        "OAuth2": {
            "type": "oauth2",
            "flows": {
                "password": {
                    "tokenUrl": "/token",
                    "scopes": {"read": "Read access", "write": "Write access"}
                }
            }
        }
    }

    # 添加全局安全要求
    openapi_schema["security"] = [{"ApiKeyAuth": []}]

    # 添加标准响应
    standard_responses = {
        "400": {
            "description": "错误请求",
            "content": {
                "application/json": {
                    "example": {
                        "status": "error",
                        "data": None,
                        "pagination": None,
                        "error": {
                            "code": "BAD_REQUEST",
                            "message": "请求参数无效",
                            "details": None
                        }
                    }
                }
            }
        },
        "401": {
            "description": "未授权",
            "content": {
                "application/json": {
                    "example": {
                        "status": "error",
                        "data": None,
                        "pagination": None,
                        "error": {
                            "code": "AUTHENTICATION_ERROR",
                            "message": "认证失败",
                            "details": None
                        }
                    }
                }
            }
        },
        # 添加其他标准响应...
    }

    # 将标准响应添加到所有路径
    for path in openapi_schema["paths"].values():
        for operation in path.values():
            if "responses" not in operation:
                operation["responses"] = {}

            # 添加标准响应（如果尚未定义）
            for status_code, response in standard_responses.items():
                if status_code not in operation["responses"]:
                    operation["responses"][status_code] = response

    app.openapi_schema = openapi_schema
    return app.openapi_schema

app.openapi = custom_openapi
```

3. 为端点添加详细文档：
```python
from fastapi import Body, Path, Query

@app.get(
    "/properties/{property_id}",
    response_model=APIResponse[PropertyDetail],
    summary="获取房产详情",
    description="根据ID获取房产的详细信息，包括基本信息、设施和图片",
    response_description="房产详情",
    tags=["房产"],
)
async def get_property(
    property_id: int = Path(..., title="房产ID", description="要获取的房产的唯一标识符", gt=0),
):
    """获取房产详情

    根据提供的ID获取房产的详细信息，包括：
    - 基本信息（标题、描述、价格等）
    - 设施列表
    - 图片URL
    - 位置信息

    如果找不到指定ID的房产，将返回404错误。

    该端点的响应会被缓存15分钟。
    """
    property_data = await get_property_by_id(property_id)
    if not property_data:
        raise HTTPException(status_code=404, detail="未找到该房产")

    return success_response(data=property_data)
```

4. 添加示例请求和响应：
```python
from fastapi import Body

@app.post(
    "/properties/",
    response_model=APIResponse[PropertyCreate],
    summary="创建新房产",
    description="创建新的房产记录",
    tags=["房产"],
)
async def create_property(
    property_data: PropertyCreate = Body(
        ...,
        examples={
            "基本示例": {
                "summary": "基本房产信息",
                "value": {
                    "title": "现代两居室公寓",
                    "description": "位于市中心的现代化两居室公寓，设施齐全",
                    "price": 500.0,
                    "bedrooms": 2,
                    "available_from": "2023-12-01"
                }
            },
            "完整示例": {
                "summary": "包含所有可选字段的完整示例",
                "value": {
                    "title": "豪华海景别墅",
                    "description": "位于海滨的豪华五居室别墅，带私人泳池和花园",
                    "price": 1500.0,
                    "bedrooms": 5,
                    "bathrooms": 3,
                    "available_from": "2023-12-15",
                    "features": ["泳池", "花园", "车库", "空调"],
                    "location": {
                        "latitude": -33.865143,
                        "longitude": 151.209900,
                        "address": "123 Beach Road, Sydney"
                    }
                }
            }
        }
    ),
    current_user = Depends(get_current_user)
):
    """创建新房产

    创建新的房产记录，需要提供基本信息如标题、描述、价格等。
    该操作需要认证，只有已登录用户才能创建房产。

    创建成功后，相关的缓存将被自动清除。
    """
    # 创建房产逻辑
    created_property = await create_new_property(property_data, current_user.id)

    # 清除缓存
    await FastAPICache.clear(namespace="properties")

    return success_response(data=created_property)
```

5. 为API添加标签和分组：
```python
app = FastAPI(
    title="优化API",
    description="增强的后端API，实现了缓存、分页、安全和异步操作",
    version="1.0.0",
    openapi_tags=[
        {
            "name": "房产",
            "description": "房产相关操作，包括创建、查询、更新和删除房产信息"
        },
        {
            "name": "用户",
            "description": "用户管理操作，包括注册、登录、个人资料管理等"
        },
        {
            "name": "通勤",
            "description": "通勤计算相关操作，包括距离和时间计算"
        },
        {
            "name": "导入",
